<?php class Model_Instruccion{	private static $_instance;		public static function getInstance()	{		if(null == self::$_instance)		{			self::$_instance = new self;		}		return self::$_instance;	}	private function __construct(){}	public function getInstruccion($nombre)	{		return Model_Mapper_Instruccion::getInstance()->getInstruccion($nombre);	}	public function getInstruccionById($id)	{		return Model_Mapper_Instruccion::getInstance()->getInstruccionById($id);	}	public function getListaNiveles()	{		return Model_Mapper_Instruccion::getInstance()->getListaNiveles();	}}